package com.baize.flux.e2e;
import com.baize.flux.api.factory.*;import com.baize.flux.engine.*;import com.baize.flux.planner.*;import com.baize.flux.plugin.*;import org.junit.jupiter.api.*;import java.sql.*;import java.util.*;import static org.junit.jupiter.api.Assertions.*;
class JdbcPipelineTest { @Test void copiesRowsBetweenMysqlCompatibleJdbcDatabases()throws Exception {String source="jdbc:h2:mem:source;MODE=MySQL;DB_CLOSE_DELAY=-1", target="jdbc:h2:mem:target;MODE=MySQL;DB_CLOSE_DELAY=-1";try(var c=DriverManager.getConnection(source);var s=c.createStatement()){s.execute("create table items(id int primary key, name varchar(20))");s.execute("insert into items values(1, 'one'),(2, 'two')");}try(var c=DriverManager.getConnection(target);var s=c.createStatement()){s.execute("create table items(id int primary key, name varchar(20))");}var registry=new FactoryRegistry(Thread.currentThread().getContextClassLoader());var sourceConnector=registry.source("jdbc").create(Map.of("url",source,"query","select id,name from items order by id"));var sink=registry.sink("jdbc").create(Map.of("url",target,"table","items","columns","id,name"));var result=new BatchPipelineExecutor().execute(new PipelinePlan(sourceConnector,List.of(),sink,1));assertEquals(2,result.rowsWritten());try(var c=DriverManager.getConnection(target);var s=c.createStatement();var rs=s.executeQuery("select count(*) from items")){rs.next();assertEquals(2,rs.getInt(1));}}}
